function initHeroSlider() {
const slides = document.querySelectorAll('.hero-slide');
const dots = document.querySelectorAll('.time-dot');
if (slides.length <= 1) return;
let current = 0;
const total = slides.length;
let timer;
function goToSlide(index) {
slides[current].classList.remove('active');
if (dots[current]) dots[current].classList.remove('active');
current = index % total;
slides[current].classList.add('active');
if (dots[current]) dots[current].classList.add('active');
}
function startTimer() {
timer = setInterval(() => goToSlide(current + 1), 7000);
}
dots.forEach(dot => {
dot.addEventListener('click', () => {
clearInterval(timer);
goToSlide(parseInt(dot.dataset.slide));
startTimer();
});
});
startTimer();
}
function initHeroParticles() {
const container = document.getElementById('heroParticles');
if (!container) return;
if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) return;
const count = window.innerWidth < 768 ? 12 : 25;
for (let i = 0; i < count; i++) {
const particle = document.createElement('div');
particle.className = 'particle';
particle.style.left = Math.random() * 100 + '%';
particle.style.top = Math.random() * 100 + '%';
particle.style.setProperty('--duration', (4 + Math.random() * 6) + 's');
particle.style.setProperty('--dx', (Math.random() * 60 - 30) + 'px');
particle.style.setProperty('--dy', (Math.random() * 60 - 30) + 'px');
particle.style.animationDelay = Math.random() * 5 + 's';
const size = (2 + Math.random() * 3) + 'px';
particle.style.width = size;
particle.style.height = size;
container.appendChild(particle);
}
}
function renderMenu() {
const tabsContainer = document.querySelector('.menu-tabs');
const contentContainer = document.querySelector('.menu-content');
if (!tabsContainer || !contentContainer) return;
tabsContainer.innerHTML = '';
contentContainer.innerHTML = '';
MENU_CATEGORIES.forEach(function(cat, i) {
const btn = document.createElement('button');
btn.className = 'menu-tab' + (i === 0 ? ' active' : '');
btn.setAttribute('data-tab', cat.id);
btn.setAttribute('role', 'tab');
btn.setAttribute('id', 'tab-' + cat.id);
btn.setAttribute('aria-controls', cat.id);
btn.setAttribute('aria-selected', i === 0 ? 'true' : 'false');
btn.textContent = cat.label;
tabsContainer.appendChild(btn);
});
MENU_CATEGORIES.forEach(function(cat, i) {
const panel = document.createElement('div');
panel.className = 'menu-panel' + (i === 0 ? ' active' : '');
panel.id = cat.id;
panel.setAttribute('role', 'tabpanel');
panel.setAttribute('aria-labelledby', 'tab-' + cat.id);
panel.setAttribute('tabindex', '0');
const catTitle = document.createElement('h3');
catTitle.className = 'menu-panel-title sr-only';
catTitle.textContent = cat.label;
panel.appendChild(catTitle);
const grid = document.createElement('div');
grid.className = 'menu-grid';
const items = MENU_ITEMS[cat.id] || [];
items.forEach(function(item) {
grid.appendChild(buildMenuItem(item));
});
panel.appendChild(grid);
if (cat.id === 'douong' && MENU_NOTES.drinks) {
const note = document.createElement('p');
note.className = 'menu-drink-note';
note.textContent = MENU_NOTES.drinks;
panel.appendChild(note);
}
contentContainer.appendChild(panel);
});
initMenuTabs();
}
function buildMenuItem(item) {
const el = document.createElement('div');
el.className = 'menu-item';
const info = document.createElement('div');
info.className = 'menu-item-info';
const nameEl = document.createElement('span');
nameEl.className = 'menu-item-name';
nameEl.textContent = item.name;
info.appendChild(nameEl);
if (item.badge) {
const badge = document.createElement('span');
badge.className = 'menu-badge hot';
badge.textContent = item.badge;
info.appendChild(badge);
}
const price = document.createElement('span');
price.className = 'menu-price';
price.textContent = item.price;
el.appendChild(info);
el.appendChild(price);
return el;
}
function initMenuTabs() {
const tabs = document.querySelectorAll('.menu-tab');
const panels = document.querySelectorAll('.menu-panel');
tabs.forEach(function(tab) {
tab.addEventListener('click', function() {
const target = tab.dataset.tab;
tabs.forEach(function(t) {
t.classList.remove('active');
t.setAttribute('aria-selected', 'false');
});
panels.forEach(function(p) { p.classList.remove('active'); });
tab.classList.add('active');
tab.setAttribute('aria-selected', 'true');
const panel = document.getElementById(target);
if (panel) panel.classList.add('active');
});
});
tabs.forEach(function(t) {
t.setAttribute('aria-selected', t.classList.contains('active') ? 'true' : 'false');
});
}
function initLazyImages() {
const lazyImages = document.querySelectorAll('img[data-src]');
if (!lazyImages.length) return;
if ('IntersectionObserver' in window) {
const observer = new IntersectionObserver(function (entries, obs) {
entries.forEach(function (entry) {
if (!entry.isIntersecting) return;
const img = entry.target;
img.src = img.dataset.src;
img.removeAttribute('data-src');
img.addEventListener('load', function () {
img.classList.add('loaded');
}, { once: true });
if (img.complete) {
img.classList.add('loaded');
}
obs.unobserve(img);
});
}, {
rootMargin: '200px 0px',
threshold: 0.01
});
lazyImages.forEach(function (img) {
observer.observe(img);
});
} else {
lazyImages.forEach(function (img) {
img.src = img.dataset.src;
img.removeAttribute('data-src');
img.addEventListener('load', function () {
img.classList.add('loaded');
}, { once: true });
if (img.complete) {
img.classList.add('loaded');
}
});
}
}
function initGalleryLightbox() {
const lightbox = document.getElementById('lightbox');
if (!lightbox) return;
const img = lightbox.querySelector('.lightbox-img');
const closeBtn = lightbox.querySelector('.lightbox-close');
const prevBtn = lightbox.querySelector('.lightbox-prev');
const nextBtn = lightbox.querySelector('.lightbox-next');
const currentEl = document.getElementById('lightboxCurrent');
const totalEl = document.getElementById('lightboxTotal');
if (!img || !closeBtn || !prevBtn || !nextBtn) return;
const items = document.querySelectorAll('.gallery-item');
const images = [];
let currentIndex = 0;
items.forEach(function (item, i) {
const imgEl = item.querySelector('img');
if (imgEl) {
const fullSrc = imgEl.dataset.src || imgEl.src;
images.push({ src: fullSrc, alt: imgEl.alt || 'Ảnh tại Trạm Dừng Chill' });
item.addEventListener('click', function () {
currentIndex = i;
showImage();
lightbox.classList.add('active');
document.body.style.overflow = 'hidden';
});
}
});
if (totalEl) totalEl.textContent = images.length;
function showImage() {
if (!images[currentIndex]) return;
img.src = images[currentIndex].src;
img.alt = images[currentIndex].alt;
if (currentEl) currentEl.textContent = currentIndex + 1;
}
function close() {
lightbox.classList.remove('active');
document.body.style.overflow = '';
}
closeBtn.addEventListener('click', close);
lightbox.addEventListener('click', function (e) { if (e.target === lightbox) close(); });
prevBtn.addEventListener('click', function (e) {
e.stopPropagation();
currentIndex = (currentIndex - 1 + images.length) % images.length;
showImage();
});
nextBtn.addEventListener('click', function (e) {
e.stopPropagation();
currentIndex = (currentIndex + 1) % images.length;
showImage();
});
document.addEventListener('keydown', function (e) {
if (!lightbox.classList.contains('active')) return;
if (e.key === 'Escape') close();
if (e.key === 'ArrowLeft') prevBtn.click();
if (e.key === 'ArrowRight') nextBtn.click();
});
let touchStartX = 0;
lightbox.addEventListener('touchstart', function (e) {
touchStartX = e.changedTouches[0].clientX;
}, { passive: true });
lightbox.addEventListener('touchmove', function (e) {
e.preventDefault();
}, { passive: false });
lightbox.addEventListener('touchend', function (e) {
const diff = touchStartX - e.changedTouches[0].clientX;
if (Math.abs(diff) > 50) {
diff > 0 ? nextBtn.click() : prevBtn.click();
}
});
}
function getTrafficSource() {
const params = new URLSearchParams(window.location.search);
const utmSource = params.get('utm_source');
const utmMedium = params.get('utm_medium');
const utmCampaign = params.get('utm_campaign');
if (utmSource) {
const source = {
source: utmSource,
medium: utmMedium || '',
campaign: utmCampaign || ''
};
sessionStorage.setItem('tdc_source', JSON.stringify(source));
return source;
}
const saved = sessionStorage.getItem('tdc_source');
if (saved) {
try { return JSON.parse(saved); } catch (e) {}
}
const ref = document.referrer;
let detected = 'direct';
if (ref.indexOf('facebook.com') !== -1 || ref.indexOf('fb.com') !== -1) detected = 'facebook_organic';
else if (ref.indexOf('tiktok.com') !== -1) detected = 'tiktok';
else if (ref.indexOf('google.') !== -1) detected = 'google_organic';
else if (ref.indexOf('zalo.') !== -1) detected = 'zalo';
else if (ref && ref.indexOf('tramdungchill.vn') === -1) detected = ref;
const source = { source: detected, medium: '', campaign: '' };
sessionStorage.setItem('tdc_source', JSON.stringify(source));
return source;
}
function initBookingForm() {
const form = document.getElementById('bookingForm');
if (!form) return;
const zaloNumber = SITE_CONFIG.contact.zaloNumber;
form.addEventListener('submit', async (e) => {
e.preventDefault();
const submitBtn = document.getElementById('submitBtn');
const btnText = submitBtn.querySelector('.btn-text');
const btnLoading = submitBtn.querySelector('.btn-loading');
const formData = new FormData(form);
const data = Object.fromEntries(formData);
if (!data.name || !data.phone || !data.date || !data.time || !data.guests) {
showNotification(t('notify.required', 'Vui lòng điền đầy đủ thông tin bắt buộc!'), 'error');
return;
}
let cleanPhone = data.phone.replace(/[\.\s\-\(\)]/g, '');
if (/^\+84/.test(cleanPhone)) cleanPhone = '0' + cleanPhone.slice(3);
if (/^84[0-9]{9}$/.test(cleanPhone)) cleanPhone = '0' + cleanPhone.slice(2);
if (!/^0[0-9]{9}$/.test(cleanPhone)) {
showNotification(t('notify.phone', 'Số điện thoại không hợp lệ (cần 10 số)!'), 'error');
return;
}
btnText.style.display = 'none';
btnLoading.style.display = 'inline';
submitBtn.disabled = true;
const message = formatZaloMessage(data);
const trafficSource = getTrafficSource();
const webhookUrl = SITE_CONFIG.webhookUrl;
let webhookOk = true;
if (webhookUrl) {
try {
await fetch(webhookUrl, {
method: 'POST',
mode: 'no-cors',
headers: { 'Content-Type': 'text/plain' },
body: JSON.stringify({
name: data.name,
phone: data.phone,
date: data.date,
time: data.time,
guests: data.guests,
occasion: data.occasion || '',
note: data.note || '',
message: message,
source: trafficSource.source,
medium: trafficSource.medium,
campaign: trafficSource.campaign,
timestamp: new Date().toISOString()
})
});
} catch (err) {
console.warn('Webhook failed:', err);
webhookOk = false;
}
}
if (typeof gtag === 'function') {
gtag('event', 'conversion_event_submit_lead_form', {});
}
const zaloUrl = 'https://zalo.me/' + zaloNumber + '?text=' + encodeURIComponent(message);
setTimeout(() => {
btnText.style.display = 'inline';
btnLoading.style.display = 'none';
submitBtn.disabled = false;
if (!webhookOk) {
showNotification(
t('notify.webhook_fail', 'Lưu đặt bàn tạm lỗi — vui lòng nhắn Zalo để xác nhận!'),
'error'
);
}
const modal = document.getElementById('successModal');
if (modal) modal.classList.add('active');
form.reset();
window.open(zaloUrl, '_blank', 'noopener,noreferrer');
}, 1000);
});
}
function formatZaloMessage(data) {
const occasionMap = {
'birthday': 'Sinh nhật',
'anniversary': 'Kỷ niệm',
'date': 'Hẹn hò',
'gathering': 'Họp mặt bạn bè',
'company': 'Công ty / team',
'other': 'Khác'
};
const [y, m, d] = data.date.split('-');
const dateStr = d + '/' + m + '/' + y;
let msg = '--- ĐẶT BÀN ONLINE ---\n';
msg += 'Tên: ' + data.name + '\n';
msg += 'SĐT: ' + data.phone + '\n';
msg += 'Ngày: ' + dateStr + '\n';
msg += 'Giờ: ' + data.time + '\n';
msg += 'Số khách: ' + data.guests + '\n';
if (data.occasion) msg += 'Dịp: ' + (occasionMap[data.occasion] || data.occasion) + '\n';
if (data.note) msg += 'Ghi chú: ' + data.note + '\n';
const src = (typeof getTrafficSource === 'function') ? getTrafficSource() : null;
if (src && src.source && src.source !== 'direct') {
msg += 'Nguồn: ' + src.source + '\n';
}
msg += '---\nĐặt qua website tramdungchill.vn';
return msg;
}
(function() {
'use strict';
function initStickyBar() {
var bar = document.getElementById('stickyBookBar');
if (!bar) return;
var hero = document.querySelector('.hero');
var heroHeight = hero ? hero.offsetHeight : 600;
var bookingSection = document.getElementById('booking');
var lastScroll = 0;
function handleScroll() {
var scrollY = window.pageYOffset;
var bookingTop = bookingSection ? bookingSection.offsetTop - 200 : Infinity;
if (scrollY > heroHeight * 0.6 && scrollY < bookingTop) {
bar.classList.add('visible');
} else {
bar.classList.remove('visible');
}
lastScroll = scrollY;
}
window.addEventListener('scroll', handleScroll, { passive: true });
handleScroll();
}
function initTikTokGallery() {
var videos = document.querySelectorAll('.tiktok-video');
if (!videos.length) return;
var loadObserver = new IntersectionObserver(function(entries) {
entries.forEach(function(entry) {
if (entry.isIntersecting) {
var video = entry.target;
var source = video.querySelector('source[data-src]');
if (source) {
source.src = source.dataset.src;
video.load();
source.removeAttribute('data-src');
}
loadObserver.unobserve(video);
}
});
}, { rootMargin: '200px' });
var playObserver = new IntersectionObserver(function(entries) {
entries.forEach(function(entry) {
var video = entry.target;
if (entry.isIntersecting && entry.intersectionRatio > 0.5) {
video.play().catch(function() {});
} else {
video.pause();
}
});
}, { threshold: [0, 0.5, 1] });
videos.forEach(function(video) {
loadObserver.observe(video);
playObserver.observe(video);
var item = video.closest('.tiktok-item');
if (item) {
item.addEventListener('mouseenter', function() {
video.play().catch(function() {});
});
item.addEventListener('mouseleave', function() {
video.currentTime = 0;
});
}
});
}
if (document.readyState === 'loading') {
document.addEventListener('DOMContentLoaded', function() {
initStickyBar();
initTikTokGallery();
});
} else {
initStickyBar();
initTikTokGallery();
}
})();
